set -Eeuo pipefail; REPO_OWNER="${REPO_OWNER:-hkzping999}"; REPO_NAME="${REPO_NAME:-Argo-Pro}"; BRANCH="${BRANCH:-main}"; ARCHIVE_URL="https://github.com/${REPO_OWNER}/${REPO_NAME}/archive/refs/heads/${BRANCH}.tar.gz"; TMP_DIR="$(mktemp -d)"; trap 'rm -rf "$TMP_DIR"' EXIT; command -v python3 >/dev/null 2>&1 || { echo "Missing python3. Please install python3 first: apt install -y python3" >&2; exit 1; }; command -v tar >/dev/null 2>&1 || { echo "Missing tar" >&2; exit 1; }; if command -v curl >/dev/null 2>&1; then curl -fsSL "$ARCHIVE_URL" -o "$TMP_DIR/source.tar.gz"; elif command -v wget >/dev/null 2>&1; then wget -qO "$TMP_DIR/source.tar.gz" "$ARCHIVE_URL"; else echo "Missing curl or wget" >&2; exit 1; fi; tar -xzf "$TMP_DIR/source.tar.gz" -C "$TMP_DIR"; SRC_DIR="$(find "$TMP_DIR" -maxdepth 1 -type d -name "${REPO_NAME}-*" | head -n 1)"; [ -n "${SRC_DIR:-}" ] && [ -d "$SRC_DIR" ] || { echo "Failed to locate extracted source directory" >&2; exit 1; }; cd "$SRC_DIR"; python3 -c 'from pathlib import Path; pats=["*.sh","*.conf","*.md","*.txt","*.json","*.yml","*.yaml",".gitattributes",".editorconfig","modules/**/*.sh","scripts/**/*.sh","tests/**/*.sh","docs/**/*.md"]; files=[]; [files.extend(Path(".").glob(p)) for p in pats]; [p.write_bytes(p.read_bytes().replace(b"\r\n",b"\n").replace(b"\r",b"\n")) for p in sorted(set(files)) if p.is_file() and b"\0" not in p.read_bytes()]'; [ -f ./argox.sh ] || { echo "argox.sh not found in repository archive" >&2; exit 1; }; chmod +x ./argox.sh; bash -n ./argox.sh; exec bash ./argox.sh "$@"
